<template>
  <van-cell-group class="long-left">
    <van-cell class="myTitle">
      <template slot="title">
        <span class="van-cell-group__title">{{label}}<b v-if='!!this.attributes.basis.maxCheckNum'>[最多选择{{this.attributes.basis.maxCheckNum}}项]</b></span>
      </template>
    </van-cell>
    <van-checkbox-group v-model="attributes.value" @change="change">
      <van-cell-group>
        <van-cell
            v-for="item in attributes.dataSource"
            clickable
            :class="{'van-cell--required':attributes.basis.required}"
            :key="item.value"
            :title="item.text"
            @click="toggle(item)"
        >
          <van-checkbox :checked-color="baseColor" :name="item.value" :disabled="attributes.basis.readOnly"/>
        </van-cell>
      </van-cell-group>
    </van-checkbox-group>
    <van-field class="other-input" v-show="showOther" v-model="attributes.otherText" placeholder="请输入"/>
  </van-cell-group>
</template>

<script>
  import base from '../../lib/base'

  export default {
    name: "CheckBox",
    extends: base,
    data() {
      return {
        showOther: false
      }
    },
    created: function () {
      //数据源是否存在
      if (this.attributes.dataSource) {
        //默认值是否存在
        if (this.attributes.basis.defaultValue) {
          if(Object.prototype.toString.call(this.attributes.basis.defaultValue)==='[object Array]'){
            let arr=[];
            for(let n in this.attributes.basis.defaultValue){
              arr.push(this.attributes.basis.defaultValue[n]['value']);
              if(this.attributes.basis.defaultValue[n]['value']==='else'){
                this.attributes.otherText=this.attributes.basis.defaultValue[n]['attach_text']
              }else{}
            }
            this.attributes.value = arr;//多选v-modal为Array
          }else{
            this.attributes.value = [this.attributes.basis.defaultValue.value];//多选v-modal为Array
          }
          this.change(this.attributes.value);
          return
        }
      } else {
        this.attributes.dataSource = [{
          text: '多选 1',
          value: 1
        }, {
          text: '多选 2',
          value: 2
        }, {
          text: '多选 3',
          value: 3
        }];
      }
      this.attributes.value = [];
    },
    computed: {},
    methods: {
      toggle(item) {
        if(this.attributes.basis.readOnly){
          return false
        }
        for (let i in this.attributes.value) {
          if (this.attributes.value[i] === item.value) {
            this.attributes.value.splice(i, 1);
            return false
          }
        }
        if (this.attributes.basis.maxCheckNum > 0 && this.attributes.basis.maxCheckNum == this.attributes.value.length) {
          this.$toast({
            message: `最多只能选择${this.attributes.basis.maxCheckNum}项`,
            duration: 1500
          });
          return
        }
        this.attributes.value.push(item.value);
      },
      change(cks) {
        this.showOther = cks.includes('else');
        this.emitParent(cks);
        this.checkTrig(cks);
      },
      checkTrig(cks) {
        if (this.attributes.basis.logic) {
          this.attributes.basis.logic.forEach((item) => {
            let state = false;
            for (let i = 0, length = item['trig'].length; i < length; i++) {
              state = this.isContained(item['trig'], cks);
              //匹配成功后中止，否则会继续匹配到trig最后一项
              if (state) {
                break;
              }
            }
            this.$emit("hidden", this.attributes['qid'], item['Q'], state);
          })
        }
      },
      //aa是否包含bb的某一项
      isContained(aa, bb) {
        if (!(aa instanceof Array) || !(bb instanceof Array)) {
          return false
        }
        for (let i = 0, length = bb.length; i < length; i++) {
          if (aa.indexOf(bb[i]) > -1) {
            return true
          }
        }
        return false
      }
    },
    components: {}
  }
</script>