<template>
  <van-cell-group>
    <van-cell v-if="attributes.basis.showLabel" class="myTitle">
      <template slot="title">
        <span class="van-cell-group__title">{{label}}</b></span>
      </template>
    </van-cell>
    <van-field
        v-model="attributes.value"
        :readonly="attributes.basis.readOnly"
        :disabled="attributes.basis.disabled"
        :placeholder="attributes.basis.readOnly?'':attributes.basis.placeholder"
        :error="attributes.error"
        :maxlength="maxlength"
        :required="attributes['basis']['required']"
        @blur="inputBlur"
        autosize
        type="textarea"
        rows="1"
        class="myInput"
    />
  </van-cell-group>
</template>

<script>
  import base from '../../lib/base'

  export default {
    extends: base,
    name: "Input",
    data() {
      return {
        validFun: null,//验证规则函数
        showError:false,//显示错误
        labelInline:true,//控制行内标签
        error:false,//是否有错误
        maxlength:200,
      }
    },
    created: function () {
      //是否隐藏行内label
      if(this.attributes.basis.hideLabel){
        this.labelInline=false;
      }
      this.maxlength = this.attributes.basis.maxL || 200;
      //默认
      this.attributes.basis.defaultValue&&(this.attributes.value = this.attributes.basis.defaultValue.text);
      this.attributes.value==null&&(this.attributes.value="");
    },
    methods: {
      inputBlur() {
        if(!this.attributes.basis.readOnly){
          this.emitParent(this.attributes.value);
        }else{
          return false
        }
      }

    },
    components: {}
  }
</script>
<style scoped>
    .myInput{
      padding-top: 0 !important;
    }
</style>