<template>
  <van-cell-group :title="label">
<!--    <van-cell v-if="attributes.basis.readOnly" :value="attributes.value||'无'"/>-->
    <van-cell class="slider-cell">
      <slot>
        <van-slider
            v-model="attributes.value"
            :max="attributes.basis.max"
            :min="attributes.basis.min"
            :step="attributes.basis.step"
            :disabled="attributes.basis.readOnly"
            :active-color="baseColor"
            @change="change"
            bar-height="4px"
        >
          <div
              slot="button"
              class="van-slider-btn"
          >{{ attributes.value }}
          </div>
        </van-slider>
      </slot>
    </van-cell>
  </van-cell-group>
</template>

<script>
  import base from '../../lib/base'

  export default {
    name: "Slider",
    extends: base,
    data() {
      return {}
    },
    computed: {},
    components: {},
    created: function () {
      this.attributes.value = this.attributes.basis.defaultValue*1;
      if (typeof this.attributes.basis.max != 'number') {
        this.attributes.basis.max = 100;
      }
      if (typeof this.attributes.basis.min != 'number') {
        this.attributes.basis.min = 0;
      }
      if (typeof this.attributes.basis.step != 'number') {
        this.attributes.basis.step = 1;
      }
      if(this.attributes.basis.min>this.attributes.value){
        this.attributes.value=this.attributes.basis.min;
      }
    },
    methods: {
      change(val){
        if(val==this.attributes.basis.max){
          this.$toast({
            message:`最大值是${this.attributes.basis.max}`,
            duration:1500
          });
        }else if(val==this.attributes.basis.min&&val!=0){
          this.$toast({
            message:`最小值是${this.attributes.basis.min}`,
            duration:1500
          });
        }else{}
      }
    }
  }
</script>
