// 组件基类
export default {
  data() {
    return {
      //蓝色：317bc7,红色：a62218
      baseColor: '#317bc7'
    }
  },
  computed: {
    label() {
      return this.attributes.basis.index ? this.attributes.basis.index + '：' + this.attributes.basis.label : this.attributes.basis.label
    }
  },
  props: ['value', 'attributes'],//attributes中包含value,单独传入一次为了emit时只用传入对应value
  created() {
    if (this.$route.path.includes('question') || location.href.includes('teas/jwgl/wjdc/qiwjdc')) this.baseColor = '#a62218';
  },
  methods: {
    //直接更改传入的value对象,父级不用监听,不直接用this.value是因为除文本框外需要值需特殊处理
    emitParent(val) {
      this.$emit("input", val);
      this.$nextTick(()=>{
        typeof window.$mobile_event.valueChange === 'function' &&  window.$mobile_event.valueChange(this.$parent.commentID,this.attributes);
      })
    },
    //根据value获取对应item索引
    getItemInArr(val, arr) {
      for (let i in arr) {
        if (arr[i]['value'] == val) {
          return i
        }
      }
      return -1
    }
  }
}
