<template>
  <div :class="['van-cell-group__title',{'van-cell--required':attributes.basis.required}]">
    {{attributes.basis.index}}：
    <template v-for="(ele,index) in html">
      {{ele}}
      <template v-if="index<html.length-1 && html.length>2">
        <input type="text" @input="setWidth" :readonly="attributes.basis.readOnly" v-model="answer['text_'+(index+1)]"
               class="van-field__control van-txt-input">
      </template>
      <template v-if="index<html.length-1 && html.length<=2">
        <input type="text" @input="setWidth" :readonly="attributes.basis.readOnly" v-model="answer"
               class="van-field__control van-txt-input">
      </template>
    </template>
    <pre ref="font"></pre>
  </div>
</template>

<script>
  import base from '../../lib/base'

  export default {
    name: "Fill",
    extends: base,
    data() {
      return {
        html: [],
        answer: {}
      }
    },
    created: function () {
      let str = this.attributes.basis.questionBody.replace(/（）/gi, '()');
      this.html = str.split("()");
      //设置默认值
      if (this.attributes.value && !!this.attributes.value) {
        this.answer = this.attributes.value;
      } else {
        if(this.html.length<=2){
          this.answer = ""
        }else{
          for (let i = 1, length = this.html.length; i < length; i++) {
            this.answer[`text_${i}`] = ""
          }
        }
      }
      //设置已填写数据
      if (this.attributes.basis.defaultValue && !!this.attributes.basis.defaultValue) {
        this.answer = this.attributes.basis.defaultValue;
      }
      this.emitParent(this.answer);
    },
    methods: {
      setWidth(e) {
        if(this.html.length<=2){
          this.emitParent(e.target.value);
        }
        this.$refs.font.innerHTML = e.target.value;
        let w = this.$refs.font.clientWidth;
        if (w < 65) {
          return
        }
        e.target.style.width = (w > 200 ? 200 : w) + 'px'
      }
    }
  }
</script>
