import Vue from 'vue';
import Vuex from 'vuex';
Vue.use(Vuex);
var state = {
  title: '',
  //页面title
  forms: [],
  //表单集合
  subForm: {},
  //表单答案
  questions: [],
  //问卷题库
  answers: {},
  //问卷答案-E调查、小程序
  btnLoading: false //提交按钮loading状态
  // numberKeyboard:false,//数字键盘

};
var mutations = {
  setTitle: function setTitle(state, title) {
    document.title = title;
    state.title = title;
  },
  //表单
  initForms: function initForms(state) {
    state.forms = [];
  },
  addForms: function addForms(state, form) {
    state.forms.push(form);
  },
  initSub: function initSub(state, sub) {
    state.subForm = sub;
  },
  setForms: function setForms(state, answers) {
    for (var key in answers) {
      state.subForm[key] = answers[key];
    }
  },
  //问卷
  initQues: function initQues(state) {
    state.questions = [];
  },
  addQues: function addQues(state, question) {
    state.questions.push(question);
  },
  initAws: function initAws(state, answer) {
    state.answers = answer;
  },
  setAws: function setAws(state, answers) {
    for (var key in answers) {
      state.answers[key] = answers[key];
    }
  }
};
var actions = {// axiosAction(context){
  //   //axios resolve
  //   context.commit("setTitle",'测试');
  // }
};
var getters = {};
export default new Vuex.Store({
  state: state,
  actions: actions,
  getters: getters,
  mutations: mutations
});