//初始数据处理相关
export default {
  data() {
    return {
      //源数据相关请求参数
      id: '',
      pageName: '',
      nameSpace: '',
      currentData: [],//当前页所有题目集合
    }
  },
  created() {
    this.id = this.$route.query.id || '';
    //判断壳环境
    if (/DreamSoft/.test(window.navigator.userAgent)) {
      window.golbalGetLayout = this.getLayout;
    } else {
      this.getLayout();
    }
  },
  beforeRouteLeave(to, from, next) {
    this.$store.state.btnLoading = false;
    next();
  },
  methods: {
    //布局数据获取
    getLayout() {
      //布局数据获取
      if (window._layout) {
        this.beforeLayout();
      } else {
        if (this.$route.query.js) {
          this.$http.get(this.$route.query.js, {
            responseType: 'text',
          }).then(str => {
            if (str) {
              this.evalGlobal(str);
              if (window._layout) {
                this.beforeLayout();
              } else {
                this.$toast({
                  message: '布局文件引入失败，请刷新后重试',
                  duration: 1500
                });
              }
            }
          });
        } else {
          this.$toast('布局文件未引入');
        }
      }
    },

    // 渲染之前操作，初始化参数，页面标题等
    beforeLayout() {
      this.$store.commit('setTitle', window._layout['$title']);
      //数据源查询参数init
      this.pageName = window._layout['$name'];
      this.nameSpace = window._layout['context']['B'] + '.' + window._layout['context']['M'];
      //开始布局
      this.layout();
    },

    // 得到layout布局文件后,开始处理渲染
    layout() {
      //这里可以从window._layout中获取到你所需要的布局文件
      //若需要获取数据源则将获取的dom数据作为参数调用getDataSource，会自行调用initDomData
      //不需要数据源的话可直接调用initDomData
      //源数据获取
      this.readDomData();
      window._layout = null;
      if (window._layoutData.length > 0) {
        this.getDataSource(window._layoutData);
        //释放暂存数据
        window._layoutData = null;
        this.layoutCallback();
      } else {
        this.$toast({
          duration: 1500,
          message: '页面数据不存在'
        });
      }
    },

    //移动端只获取center与buttom布局中的布局元素
    readDomData() {
      // 索引关系=>0：中间，1：顶部，2：底部
      let center = this.getDomList(window._layout['children'][0]['children']);
      let top = this.getDomList(window._layout['children'][1]['children']);
      let bottom = this.getDomList(window._layout['children'][2]['children']);
      top = top.concat(center);
      window._layoutData = top.concat(bottom);
    },

    /**
     * 获取源数据
     * @param dom 原页面数据
     */
    getDataSource(dom) {
      //数据源请求
      if (window['_DsfOffLine']) {
        let _this = this;
        window._DsfOffLine.init({
              id: _this.id,
              pageName: _this.pageName,
              namespace: _this.nameSpace,
            }, function (res) {
              console.info('initCallback:', res);
              (res && res.success == true && res.state == 20000) && _this.getSaveData(dom, res.data);
            },
            function (err) {
              console.log(err);
              _this.$toast((err&&err.data&&err.data.message)?err.data.message:'初始化源数据请求失败')
            });
      } else {
        this.$http.get('dsfa/meta/init', {
          params: {
            id: this.id,
            pageName: this.pageName,
            namespace: this.nameSpace
          }
        }).then(source => {
          source && this.getSaveData(dom, source.data);
        });
      }
    },

    /**
     * 获取已提交的数据
     */
    getSaveData(dom, source) {
      if (window['_DsfOffLine']) {
        let _this = this;
        window._DsfOffLine.query({
          id: _this.id,
          data: {"_id": _this.id},
          pageName: _this.pageName,
          namespace: _this.nameSpace,
        }, function (res) {
          (res && res.success == true && res.state == 20000) && _this.dealSaveData(res.data, source, dom);
        }, function (err) {
          console.log(err);
          _this.$toast((err&&err.data&&err.data.message)?err.data.message:'数据请求失败')
        });
      } else {
        this.$http.get('dsfa/meta/data', {
          params: {
            id: this.id,
            data: {"_id": this.id},
            pageName: this.pageName,
            namespace: this.nameSpace
          }
        }).then(data => {
          data && this.dealSaveData(data.data, source, dom);
        });
      }
    },

    // 已保存的data数据处理
    dealSaveData(data, source, dom) {
      if (this.$route.name === 'Form') {
        this.$store.commit('initSub', data);//设置form答案
      } else if (this.$route.name === 'Question') {
        this.$store.commit('initAws', data);//设置question答案
      } else {
      }
      //暴露
      window.pageServerData = JSON.parse(JSON.stringify(data));
      this.initDomData(dom, source);
    },

    //点击事件监听
    btnClick(type,btn) {
      if (type === 'save') {
        this.next(btn);
      }else if(typeof window.$mobile_event.button_click==='function'){
        window.$mobile_event.button_click(btn)
      }
    },

    //js解析函数
    evalGlobal(strScript) {
      if (window.execScript) window.execScript(strScript);
      else window.eval(strScript);
    },

    // 获取最后一个子集下的Dom集合
    getDomList(data) {
      if (data['children'] && data['children'][0] && data['children'][0]['children']) {
        //递归每次获取当前元素集合下第一个元素的子集
        this.getDomList(data['children'][0]['children']);
      } else {
        return data || [];
      }
    },

    // --------------------需重写的方法------------------
    /**
     * 问卷数据组合
     * @param dom 原页面数据
     * @param dataSource 表单源数据
     */
    initDomData(dom, dataSource) {
      //渲染界面或操作渲染数据
      console.error("请重写组件所用的DOM数据处理方法");
    },
    //渲染完成后回调
    layoutCallback() {

    }
  }
}
