import base from "../../lib/base";
export default {
  name: "Select",
  extends: base,
  data: function data() {
    return {
      show: false,
      selected: 0 //索引，select选中控制

    };
  },
  created: function created() {
    //初始化items以及默认值
    if (!this.attributes.dataSource) {
      this.attributes.dataSource = [{
        text: 'Select 1',
        value: 1
      }, {
        text: 'Select 2',
        value: 2
      }, {
        text: 'Select 3',
        value: 3
      }];
      this.attributes.value = "";
    } else {
      if (this.attributes.basis.defaultValue) {
        this.attributes.value = this.attributes.basis.defaultValue;

        for (var i in this.attributes.dataSource) {
          if (this.attributes.dataSource[i]['value'] === this.attributes.value.value) {
            this.selected = +i;
            return;
          }
        }
      }
    }

    this.attributes.errorMsg = "\u8BF7\u9009\u62E9".concat(this.attributes.basis.label);
  },
  computed: {
    showTxt: function showTxt() {
      if (!!this.attributes.value || this.attributes.value === 0) {
        return this.attributes.dataSource[this.selected]['text'];
      } else {
        return '';
      }
    }
  },
  methods: {
    onConfirm: function onConfirm(val, index) {
      this.selected = index;
      this.attributes.value = val;
      this.show = false;
      this.attributes.error = false;
      debugger;
      this.emitParent(val);
    },
    onCancel: function onCancel() {
      this.show = false;
    }
  },
  components: {}
};