<template>
  <div v-if="question.basis.visible" :id="question.basis.id" :class="['question',{'question-btn-box':componentName==='buttonBar'}]">
    <div v-show="!question.hidden">
      <component v-if="question.basis.bindValue" :is="componentName" v-model="question.value" v-on="$listeners"
                 :attributes="question"></component>
      <!--按钮组需要监听事件分发-->
      <component v-else-if="componentName==='buttonBar'" :is="componentName" :attributes="question"
                 v-on="$listeners"></component>
      <component v-else :is="componentName" :attributes="question" title="testAttr" align="left"></component>
    </div>
  </div>
</template>

<script>
  import Qa from '@/components/question/Qa'
  import Radio from '@/components/question/Radio'
  import Select from '@/components/bhc/Select'
  import CheckBox from '@/components/question/CheckBox'
  import Rate from '@/components/question/Rate'
  import Slider from '@/components/question/Slider'
  import Fill from '@/components/question/Fill'
  import Label from '@/components/common/Label'
  import ButtonBar from '@/components/common/ButtonBar'
  // import DataChoice from '@/components/common/DataChoice'

  // import DatePicker from '@/components/bhc/DatePicker'
  // import DateIntervalPicker from '@/components/bhc/DateIntervalPicker'
  // import Uploader from '@/components/bhc/Uploader'

  export default {
    name: "Question",
    props: {
      question: {
        type: Object,
        default() {
          return {}
        }
      }
    },
    data() {
      return {}
    },
    components: {
      qACrl: Qa,
      radioCrl: Radio,
      selectCrl: Select,
      checkBoxCrl: CheckBox,
      rate: Rate,
      slider: Slider,
      labelCrl: Label,
      buttonBar: ButtonBar,
      fill: Fill,
      // dataChoice: DataChoice,
      // uploader:Uploader,
      // datePickerCrl:DatePicker,
      // dateIntervalPicker:DateIntervalPicker
    },
    computed: {
      //重命名注册组件的原因：一些组件参数需要修改并且指向同一或不同组件
      componentName: function () {
        //是否存在
        if (this.question.basis.ctrl_type) {
          switch (this.question.basis.ctrl_type) {
            case 'Section':
              return ''
            case 'QsRadio':
              return 'radioCrl'
            case 'QsSelect':
              return 'selectCrl'
            case 'QsCheckBox':
              return 'checkBoxCrl'
            case 'QA':
              return 'qACrl'
            case 'ButtonBar':
              return 'buttonBar'
            case 'QsSlider':
              return 'slider'
            case 'QsRate':
              return 'rate'
            case 'QsHelloMsg':
              return 'labelCrl'
            case 'Datepicker':
            case 'TimePicker':
              return 'datePickerCrl'
            case 'DateIntervalPicker':
              return 'dateIntervalPicker'
            case 'UploadPhoto':
            case 'UploadImg':
              return 'uploader'
            case 'Fill':
              return 'fill'
          }
        }
        else {
          return ''
        }
      }
    },
    methods: {}
  }
</script>
