<template>
  <van-cell-group :title="groupLabel">
    <van-cell>
      <slot>
        <van-rate :icon="icon" :size="24" :void-icon="vicon" :allow-half="true" v-model="attributes.value"
                  :count="attributes.basis.count" :readonly="attributes.basis.readOnly" :color="baseColor" @change="change"/>
      </slot>
    </van-cell>
  </van-cell-group>
</template>

<script>
  import base from '../../lib/base'

  export default {
    name: "Rate",
    extends: base,
    data() {
      return {
        icon: 'star'
      }
    },
    computed: {
      vicon: function () {
        return this.icon + '-o'
      },
      groupLabel:function () {
        return this.label+" ("+this.attributes.value+")";
      }
    },
    components: {},
    created: function () {
      // if (isNaN(this.attributes.value)) {
      //   this.attributes.value = 0;
      // }else{
      //   this.attributes.value=+this.attributes.value;
      // }
      this.attributes.value = isNaN(this.attributes.basis.defaultValue)?0:this.attributes.basis.defaultValue*1;
      if (isNaN(this.attributes.basis.count)) {
        this.attributes.basis.count = 5;
      }else{
        this.attributes.basis.count=+this.attributes.basis.count;
      }
      if (this.attributes.basis.rateType === 'like') {
        this.attributes.basis.icon = 'like';
      }
    },
    methods: {
      change(num) {
        this.emitParent(num);
      }
    }
  }
</script>
