//提交与保存数据相关
export default {
  data() {
    return {
      btnTxt: '下一页', //按钮显示文字
      isLast: false,//是否是最后一页
      firstErr: null,//第一个错误
      saveTime: 0,//上一次提交时间，1秒内不进行处理
      notNull: true,//必填已全部填写
    }
  },
  created() {
    window.$mobile_event.save = this.save;
    window.$mobile_event.saveZc = this.saveZc;
  },
  methods: {
    $extend_obj(newObj,obj) {
      if(newObj){
        newObj = JSON.parse(JSON.stringify(newObj));
      }
      if(obj){
        for(let k in obj){
          newObj[k] = obj[k];
        }
      }
      return newObj;
    },
    //下一步或提交事件
    next(btn) {
      if ((Date.now() - this.saveTime) / 1000 < 1 || this.$store.state.btnLoading) {
        return false
      }
      this.saveTime = Date.now();
      //twoOpenCheck：二次开发验证数据集合
      //answer：提交数据集合
      let twoOpenCheck = {},answer = {};

      //判断是否到了最后一页允许提交
      if (this.isLast) {
        //提交验证:首先进行本地验证以及开始拼值，然后审核验证存在规则再进行审核验证
        let checkResult = this.checkData(answer, twoOpenCheck);
        //在审核时如果本地验证出现的错误是由于上一次审核出现的，本次审核若pageCurrent对象无任何错误，则忽略第一次本地验证结果
        //审核存在执行审核，否则默认出现错误，使用本地验证规则
        let noErr = true;
        if (window.ev && window.ev.evList.length > 0 && window.pageCurrentData && window.pageCurrentData instanceof Array) {
          //加入二次开发验证,num1必要性level=1\num0提示性level=0
          let isPass = true;
          //执行审核
          window.ev.exec(twoOpenCheck);
          //回收检验对象
          twoOpenCheck = null;
          //存储一份需要必填备注的审核数据key
          window.reqiureRemarkList = {};
          //重置审核结果
          let auditResult = [];
          if (this.auditInfo) {
            this.auditInfo.result['num1'] = 0;
            this.auditInfo.result['num0'] = 0;
            for (let i = 0, length = window.pageCurrentData.length; i < length; i++) {
              //跳过非数据项与被排除的项
              if (!window.pageCurrentData[i]['basis']['id'] || window.pageCurrentData[i]['exclude'] == true) {
                continue
              }
              if (window.pageCurrentData[i]['basis']['ctrl_type'] === 'SubTableVertical') {
                for (var n = 0, subLength = window.pageCurrentData[i]['items'].length; n < subLength; n++) {
                  //遍历每个小子表的每一项
                  for (let c = 0, childLength = window.pageCurrentData[i]['items'][n].length; c < childLength; c++) {
                    //检验完成父级对象
                    let subs = window.ev.evResult[window.pageCurrentData[i]['basis']['caption']];
                    if (!subs) {
                      continue
                    }
                    //设置是否需要必填备注
                    window.reqiureRemarkList[window.pageCurrentData[i]['items'][n][c]['basis']['caption']] = window.pageCurrentData[i]['items'][n][c]['basis']['requireRemark'];
                    //跳过子表中非数据项与被排除的项
                    if (window.pageCurrentData[i]['items'][n][c]['exclude'] == false && window.pageCurrentData[i]['items'][n][c]['basis']['id']) {
                      //子表下的每一个小子表tab
                      let subObj = subs[n];
                      let result = this.findEvCtrlArray(auditResult, window.pageCurrentData[i]['items'][n][c]['basis']['caption'], subObj, n);
                      //检测结果存在
                      if (result.length > 0) {
                        //验证结果以及定位到第一个错误
                        result.map((item) => {
                          if (item.audit.ok == false) {
                            item.audit.level == 1 && (isPass = false);
                            this.auditInfo && item.audit.level === 1 ? this.auditInfo.result['num1']++ : this.auditInfo.result['num0']++;
                          }
                        });
                      }
                    }
                    (window.pageCurrentData[i]['items'][n][c]['error'] && !window.pageCurrentData[i]['items'][n][c]['exclude']) && (noErr = false);
                  }
                }
              } else {
                //是否需要审核备注
                window.reqiureRemarkList[window.pageCurrentData[i]['basis']['caption']] = window.pageCurrentData[i]['basis']['requireRemark'];
                let result = this.findEvCtrlArray(auditResult, window.pageCurrentData[i]['basis']['caption']);
                if (result.length > 0) {
                  result.map((item) => {
                    if (item.audit.ok == false) {
                      item.audit.level == 1 && (isPass = false);
                      this.auditInfo && item.audit.level === 1 ? this.auditInfo.result['num1']++ : this.auditInfo.result['num0']++;
                    }
                  });
                }
                (window.pageCurrentData[i]['error'] && !window.pageCurrentData[i]['exclude']) && (noErr = false);
              }
            }
            //赋值新的审核结果
            this.auditInfo.result.detail = auditResult;
            auditResult = null;
            //重置检验结果
            window.ev.evResult = {};
          }
          
          this.review = false;
          //审核结果
          if (this.auditInfo) {
            this.auditInfo.result.state = 1;
            //必要性错误显示审核结果
            if (this.auditInfo.result.num1 > 0) {
              this.review = true;
              this.auditInfo.result.state = -1;
              this.goFirstErr(true);
              // return
            }else if (this.auditInfo.result.detail instanceof Array) {
              //检验提示性审核是否填写了必填的备注
              for (let i = 0, length = this.auditInfo.result.detail.length; i < length; i++) {
                if (!window.reqiureRemarkList[this.auditInfo.result.detail[i]['key']] && !this.auditInfo.result.detail[i]['remark'] && this.auditInfo.result.detail[i]['level'] == 0) {
                  this.review = true;
                  this.$toast({
                    message: `${this.auditInfo.result.detail[i]['errorMsg']}，请输入审核信息`,
                    duration: 1500
                  });
                  this.goFirstErr(false);
                  this.auditInfo.result.state = -1;
                  // return
                }
              }
            }
          }
          if (!isPass) {
            this.goFirstErr(true);
            // return
          }
        }else {
          twoOpenCheck = {};
          noErr = false;
        }
        // 通过审核后再判断是否通过本地验证
        if (!checkResult && !noErr) {
          //定位到首个错误元素
          this.firstErr && this.goFirstErr(true);
          return false
        }
        // else {
          //将state中的特殊数据赋值到提交对象(比如说隐藏的数据，没有显示在页面上的数据)
          this.copyData(answer, (this.isQuestion ? this.$store.state.answers : this.$store.state.subForm));
          this.auditInfo && (answer[this.auditInfo.id] = this.auditInfo.result);
          //保存请求,若链接参数存在_id使用，_id判断是更新还是新增
          answer['_id'] = this.id;

          // ---------------------- 红网小程序 start ----------------------
          //手动设置状态，时间
          let beginStr = this.nameSpace.replace(/\./g, "_");
          if (answer[beginStr + '.pjsj'] !== undefined) {
            answer[beginStr + '.pjsj'] = new Date().Format('yyyy-MM-dd hh:mm:ss');
          }
          if (answer[beginStr + '.pjzt'] !== undefined) {
            answer[beginStr + '.pjzt'] = {
              text: '是',
              value: '1'
            };
          }
          //入学调查特殊处理
          if (answer[beginStr + '.teas_jwgl_bjxygl_id'] !== undefined) {
            answer[beginStr + '.teas_jwgl_bjxygl_id'] = this.id;
          }
          // ---------------------- 红网小程序 end ----------------------

          //是否需要将审核结果赋值到子表
          if (this.auditInfo && this.auditInfo.isSyncChildList && window.SubTableVertical && answer[window.SubTableVertical]) {
            for (let i = 0, length = answer[window.SubTableVertical].length; i < length; i++) {
              //判断是否含有已删除子表标识id
              if (!answer[window.SubTableVertical][i][window.SubTableVertical + '.ds_deleted']) {
                answer[window.SubTableVertical][i][window.SubTableVertical + '.auditinfo'] = {
                  state: this.auditInfo.result.state,
                  num0: this.auditInfo.result['num0'] || 0,
                  num1: this.auditInfo.result['num1'] || 0,
                  detail: '[]'
                }
              }
            }
          }
          //二次开发提交数据处理
          if (typeof window.checkSubData === 'function') {
            let ok = window.checkSubData(answer,btn.alias,btn);
            if (ok === false) {
              return
            }
          }
          console.log(answer);
          //记录提交时间，设置loading
          let _this = this;
          this.save({
            id: _this.id,
            pageName: _this.pageName,
            namespace: _this.nameSpace,
            data: JSON.stringify(answer)
          }, {
            message: (_this.auditInfo && _this.auditInfo.result && _this.auditInfo.result.state==-1)?undefined:(btn && btn.text)?btn.text:'保存',
            isSaveBtn:true,
            alias: btn.alias
          })
      } else {
        //多页翻页
        // if (this.checkData(answer, twoOpenCheck)) {
        //   //判断路由
        //   if (this.isQuestion) {
        //     this.$store.commit("setAws", answer);
        //   } else {
        //     this.$store.commit("setForms", answer);
        //   }
        //   this.saveTime = Date.now();
        //   let path = this.$route.path;
        //   this.$router.push({ path: path === '/' ? '/index/next' : path + '/next' });
        // }
      }
    },
    /**
     * 暂存
     * opts:{
     *   btn:按钮信息
     *   message:String
     *   succback:Function
     *   failback:Function 
     * }
     * */
    saveZc(opts) {
      opts = opts || {};
      opts.isZcButtom = true;
      if (this.auditInfo) {
        let answer = {};
        this.checkData(answer, {},true);
        this.copyData(answer, (this.isQuestion ? this.$store.state.answers : this.$store.state.subForm));
        answer['_id'] = this.id;
        answer[this.auditInfo.id] = {
          state: -2,
          num0: 0,
          num1: 0,
          detail: '[]'
        };
        if (this.auditInfo && this.auditInfo.isSyncChildList && window.SubTableVertical && answer[window.SubTableVertical]) {
          for (let i = 0, length = answer[window.SubTableVertical].length; i < length; i++) {
            answer[window.SubTableVertical][i][window.SubTableVertical + '.auditinfo'] = {
              state: -2,
              num0: 0,
              num1: 0,
              detail: '[]'
            }
          }
        }

        // 保存前
        if (typeof window.checkSubData === 'function') {
          let ok = window.checkSubData(answer, opts.btn ? opts.btn.alias : undefined, opts.btn);
          if (ok === false) {
            return
          }
        }
        // 保存
        this.save({
          id: this.id,
          pageName: this.pageName,
          namespace: this.nameSpace,
          data: JSON.stringify(answer)
        }, opts)
      } else {
        this.$toast({
          message: '暂存失败',
          icon: 'fail'
        });
      }
    },
    save(param, opts) {
      let _this = this;
      if(!(opts && opts.isZcButtom)){
        _this.$store.state.btnLoading = true;
      }
      if (window['_DsfOffLine']) {
        window._DsfOffLine.save(param, function (res) {
          _this.saveSucc.call(_this, _this.$extend_obj({response: res},opts));
        }, function (err) {
          _this.saveFail.call(_this, _this.$extend_obj({response: err},opts));
        });
      } else {
        _this.$http.post("dsfa/meta/persistData", param).catch(err => {
          _this.saveFail.call(_this, _this.$extend_obj({response: err},opts));
        }).then((res) => {
          _this.saveSucc.call(_this, _this.$extend_obj({response: res},opts));
        });
      }
    },
    saveSucc(opts) {
      if(opts.response.data){
        window.pageServerData = JSON.parse(JSON.stringify(opts.response.data));
      }
      let data = this.$extend_obj(opts.response);
      let res = data.data;
      if(opts.isSaveBtn || opts.isZcButtom){
        if(res['_id']){
          this.id = res['_id']
        }
        //将store的_id相关值赋值到answer
        this.$store.commit("setForms", this.$extend_obj(res));
        //将子表中每个的_id赋值到currentPage数据
        for (let i = 0, length = this.currentData.length; i < length; i++) {
          if (this.currentData[i]['basis']['ctrl_type'] === 'SubTableVertical') {
            for (let n = 0, subLength = this.currentData[i]['items'].length; n < subLength; n++) {
              let subItem = res[this.currentData[i]['basis']['id']][n];
              for (let subKey in subItem) {
                //给子表下小子表的第一个表单项增加_id
                subKey.includes('_id') && (this.currentData[i]['items'][n][0][subKey] = subItem[subKey]);
              }
            }
          }
        }
      }
      // 红网问卷保存后就只读
      if(this.isQuestion){
        this.changeReadonly(1);
      }else{
        this.$store.state.btnLoading = false;
      }
      // 保存成功之后
      if(opts.message){
        this.$toast.success({
          message: opts.message + '成功',
          duration: 2000,
          onClose: function () {
            window.wx && (window.wx.miniProgram.navigateBack());
          }
        });
      }
      if (opts.isSaveBtn) {
        typeof window.$mobile_event.saveComplate === 'function' && window.$mobile_event.saveComplate(data,{
          alias: opts.alias
        });
      } else {
        typeof opts.succback === 'function' && opts.succback(data);
      }
    },
    saveFail(opts){
      if (opts.isSaveBtn) {
        typeof window.$mobile_event.saveComplate === 'function' && window.$mobile_event.saveComplate(opts.response,{
          alias: opts.alias
        });
      } else {
        typeof opts.failback === 'function' && opts.failback(opts.response);
      }
      this.$store.state.btnLoading = false;
      if(opts.message){
        let err = opts.response
        this.$toast((err && err.data && err.data.message) ? err.data.message : opts.message + '失败');
      }
    },
    
    /**
     * 数据检测以及提交内容获取
     * @param answer 提交的数据格式
     * @param twoOpenCheck 用于二次开发验证的数据格式
     * @returns {boolean}
     */
    checkData(answer, twoOpenCheck,isZc) {
      if (!answer instanceof Object || !twoOpenCheck instanceof Object) {
        throw '参数只能是对象'
      }
      //每页每道题答案收集,每次验证前重置必填
      let error = false;
      this.notNull = true;
      this.firstErr = null;
      for (let i = 0, currentLen = this.currentData.length; i < currentLen; i++) {
        //必填检测与提交数据赋值:若控件不存在标识id或被隐藏，不进行
        if (this.hasIdOrShow(this.currentData[i])) {
          let hasError = this.requireAndSetVal(this.currentData[i], answer, twoOpenCheck, i,undefined,isZc);
          hasError === false && (error = true);
        } else if (this.currentData[i]['basis']['ctrl_type'] === 'SubTableVertical') {
          //子表的特殊处理sub:answer  checkSub:twoOpenCheck
          let sub = [], checkSub = [];
          //赋值新增和修改的项
          for (let n = 0, subLength = this.currentData[i]['items'].length; n < subLength; n++) {
            //每一个子表的小子表数据集合,key=>id,val=>填写的数据
            let obj = {}, checkObj = {};
            for (let childNum = 0, childLength = this.currentData[i]['items'][n].length; childNum < childLength; childNum++) {
              let hasError;
              this.hasIdOrShow(this.currentData[i]['items'][n][childNum]) && (hasError = this.requireAndSetVal(this.currentData[i]['items'][n][childNum], obj, checkObj, i, n,isZc));
              hasError === false && (error = true);
            }
            //子表_id相关字段赋值
            obj['_id'] = this.currentData[i]['items'][n][0]['_id'] || "";
            obj[this.currentData[i]['basis']['id'] + '.' + this.currentData[i]['basis']['id'] + '_id'] = obj['_id'];
            sub.push(obj);    
            checkSub.push(checkObj);
          }
          twoOpenCheck[this.currentData[i]['basis']['id'].replace((this.nameSpace.replace(/\./g, '_') + '_'), '')] = checkSub;
          //赋值删除的子表子数据id,检测的对象不进行此操作
          let all = sub.concat(this.currentData[i]['delete']);
          answer[this.currentData[i]['basis']['id']] = all;
        }
      }
      if(isZc){
        // 暂存
        return
      }
      //填写未完成
      if (!this.notNull) {
        //是否问卷
        if (this.$route.path.includes('question')) {
          for (let i = 0, length = this.currentData.length; i < length; i++) {
            if (this.currentData[i]['error']) {
              this.$toast({
                duration: 1500,
                message: this.currentData[i]['errorMsg']
              });
              return false
            } else {
            }
          }
        } else{
          this.goFirstErr(false);
          this.$toast({
            duration: 1500,
            message: '请完成全部必填项'
          });
          return false
        }
      } else if (error) {
        return false
      } else {
        return true
      }
    },
    /**
     * 检测必填与赋值函数
     * @param current 当前数据项
     * @param answer 提交数据集合
     * @param twoOpenCheck 二次开发验证数据集合
     * @param itemIndex 子表的索引
     * @param index 表单项索引
     * @returns {boolean}
     */
    requireAndSetVal(current, answer, twoOpenCheck, index, itemIndex,isZc) {
      current['error'] = false;
      //判断没被排除的、且必填的数据是否有值
      if (!current['exclude'] && (current['basis']['validate'] && current['basis']['validate']['required']) && current['basis']['readOnly'] == false) {
        //这里的value有多种类型，checkbox为array，select、radio为object
        if (current['value'] instanceof Array) {
          if (current['value'].length === 0) {
            if(!isZc){
              current['error'] = true;
              this.notNull = false;
            }
          }
        } else if (current['value'] instanceof Object) {
          let exit = true;
          for (let k in current['value']) {
            if (current['value'][k]) {
              exit = false;
              break;
            }
          }
          if(!isZc){
            exit && (current['error'] = true, this.notNull = false);
          }
        } else {
          if (!current['value'] && typeof current['value'] != 'number' && typeof current['value'] != 'boolean') {
            if(!isZc) {
              current['error'] = true;
              this.notNull = false;
            }
          }
        }
      } 

      //首错误（用于定位）
      if(!isZc){
        let isFirst = false;
        if (current['error'] && !this.firstErr) {
          isFirst = true;
          this.firstErr = {
            id: current['basis']['id'],
            index: index,
            msg: current['errorMsg'],
            pid: current['basis']['pid'] || '',
            itemIndex: itemIndex || 0
          }
        }
      }

      //值设置
      let cid = current['basis']['id'];
      // 有pid的代表是子表
      let tid = cid.replace(((current['basis']['pid'] ? current['basis']['pid'] : this.nameSpace.replace(/\./g, '_')) + '.'), '');
      //被隐藏排除，answer直接赋空值，否则去获取
      if (current['exclude'] === true) {
        //根据类型赋值
        if (current['basis']['ctrl_type'].includes('CheckBox')) {
          answer[cid] = [];
        } else if (current['basis']['ctrl_type'].includes('Radio') || current['basis']['ctrl_type'].includes('Select')) {
          answer[cid] = {
            text: '',
            value: ''
          };
        } else {
          answer[cid] = "";
        }
        twoOpenCheck[tid] = answer[cid];
      } else if (current['basis']['readOnly'] == true) {
        answer[cid] = current['value'];
        twoOpenCheck[tid] = answer[cid];
      } else {
        //评分验证特殊处理
        if (current['basis']['ctrl_type'] === 'Rank') {
          let rank = {};
          rank['total'] = (+current['rowSet']['total']).toFixed(2);
          for (let k = 0, length = current['rowSet']['rows'].length; k < length; k++) {
            //验证
            //只有一级选项
            if (!current['rowSet']['rows'][k]['children']) {
              if (!current['rowSet']['rows'][k]['score']) {
                this.$toast({
                  duration: 1500,
                  message: '请完成全部评价'
                });
                return false
              }
            } else {
              for (let rowChild in current['rowSet']['rows'][k]['children']) {
                if (!current['rowSet']['rows'][k]['children'][rowChild]['score']) {
                  this.$toast({
                    duration: 1500,
                    message: '请完成全部评价'
                  });
                  return false
                }
              }
            }
            rank['xm_' + (k + 1)] = current['rowSet']['rows'][k]['project'];
            current['rowSet']['norm'] == 1 && (rank['bz_' + (k + 1)] = current['rowSet']['rows'][k]['norm']);
            rank['pf_' + (k + 1)] = (+current['rowSet']['rows'][k]['score']).toFixed(2);
            current['rowSet']['weight'] == 1 && (rank['qz_' + (k + 1)] = current['rowSet']['rows'][k]['weight']);
            //二级
            if (current['rowSet']['rows'][k]['children']) {
              for (let n = 0, len = current['rowSet']['rows'][k]['children'].length; n < len; n++) {
                if (!current['rowSet']['rows'][k]['children'][n]['score']) {
                  this.$toast({
                    duration: 1500,
                    message: '请完成全部评价'
                  });
                  return false
                }
                rank['xm_' + (k + 1) + '_' + (n + 1)] = current['rowSet']['rows'][k]['children'][n]['project'];
                current['rowSet']['norm'] == 1 && (rank['bz_' + (k + 1) + '_' + (n + 1)] = current['rowSet']['rows'][k]['children'][n]['norm']);
                rank['pf_' + (k + 1) + '_' + (n + 1)] = current['rowSet']['rows'][k]['children'][n]['score'];
                current['rowSet']['weight'] == 1 && (rank['qz_' + (k + 1) + '_' + (n + 1)] = current['rowSet']['rows'][k]['children'][n]['weight']);
              }
            }
          }
          answer[cid] = rank;
          twoOpenCheck[tid] = answer[cid];
        } else {
          //判断是否是含有数据源的题目，有数据源的value需要从数据源查找对应值
          if (!!current['dataSource'] && current['dataSource'] instanceof Array && current['dataSource'].length > 0) {
            if (current['basis']['ctrl_type'].includes('Select')) {
              answer[cid] = (current['value'] && current['value'].value)?current['value']:{text:"",value:""};
            } else {
              //多选单选
              answer[cid] = this.getAnswer(current);
            }
          } else {
            //文本框类型
            answer[cid] = current['value'];
          }
          twoOpenCheck[tid] = answer[cid];
        }
      }

      if (current['error']) {
        return false
      }
    },
    //验证:若控件不存在标识id或被隐藏，不进行检测
    hasIdOrShow(data) {
      return (data['basis']['id'] && data['basis']['visible']) ? true : false
    },
    //获取当前题答案
    getAnswer(qObj) {
      let val = qObj['value'], source = qObj['dataSource'];
      //单选还是多选，多选题value为数组
      if (val instanceof Array) {
        let answer = [];
        for (let i in val) {
          for (let n in source) {
            if (source[n]['value'] == val[i]) {
              val[i] == 'else' && (source[n]['attach_text'] = qObj['otherText']);
              delete source[n]['$$hashKey'];
              answer.push(source[n]);
              break;
            }
          }
        }
        return answer
      } else {
        for (let n in source) {
          if (source[n]['value'] == val) {
            val == 'else' && (source[n]['attach_text'] = qObj['otherText']);
            return source[n]
          }
        }
        return {
          value: '',
          text: ''
        }
      }
    },
    //定位第一个错误
    goFirstErr(showMsg) {
      let eid = this.firstErr.id.replace(/\./g, "-");
      if (this.firstErr.pid) {
        eid += ('--' + window.pageCurrentData[this.firstErr.index]['element'][this.firstErr.itemIndex]['eleId']);
        window.pageCurrentData[this.firstErr.index]['active'] = this.firstErr.itemIndex;
        eid = this.firstErr.pid+"-"+eid;
      }
      if (showMsg) {
        this.$toast({
          duration: 1500,
          message: this.firstErr.msg || '验证失败'
        });
      }
      this.$nextTick(function () {
        let ele = document.getElementById(eid);
        //{behavior: "smooth"}滑动效果
        ele && ele.scrollIntoView();
        this.firstErr = null;
      });
    },
    //只处理第一层数据的_id且answer不存在的值，将state赋值到answer
    copyData(answer, state) {
      for (let key in state) {
        (key.includes('_id') || answer[key] == null || answer[key] == undefined) && (answer[key] = state[key] == null ? "" : state[key]);
      }
    },
    /**
     * 通过key查找对应审核规则,更改页面数据,返回结果集
     * @param auditResult 结果集
     * @param id 控件id
     * @param subs 子表审核结果集
     * @param index 所在子表tab索引
     * @returns {Array}
     */
    findEvCtrlArray(auditResult, id, subs, index) {
      let result = [];
      for (let i = 0, length = window.ev.evList.length; i < length; i++) {
        for (let j = 0, evLength = window.ev.evList[i]['rel'].length; j < evLength; j++) {
          if (window.ev.evList[i]['rel'][j] === id) {
            let key = window.ev.evList[i]['key'];
            let item = subs ? subs[key] : window.ev.evResult[key];
            if (item) {
              let obj = {
                key: key,
                index: index,
                audit: item
              };
              //检查当前审核结果集是否已经存在key
              let relLength = auditResult.length;
              for (var n = 0; n < relLength; n++) {
                if (auditResult[n]['key'] === key && auditResult[n]['index'] == index) {
                  break;
                }
              }
              (n === relLength) && result.push(obj);
              this.updatePageError(id, obj, auditResult, window.ev.evList[i]['rel'], !(n === relLength));
              break;
            }
          }
        }
      }
      return result
    },
    /**
     * 审核错误后更新界面显示
     * @param id 当前题目id
     * @param result 当前审核结果
     * @param auditResult 新的审核结果集
     * @param elements 审核结果影响的元素id集合
     * @param exist 当前审核集是否已经存在当前审核的key
     */
    updatePageError(id, result, auditResult, elements, exist) {
      for (let j = 0, length = elements.length; j < length; j++) {
        for (let i = 0, pageLength = window.pageCurrentData.length; i < pageLength; i++) {
          //子表
          if (result.audit.pid && window.pageCurrentData[i]['basis']['ctrl_type'] === 'SubTableVertical' && window.pageCurrentData[i]['basis']['caption'] === result.audit.pid) {
            for (let n = 0, subLength = window.pageCurrentData[i]['items'][result.index].length; n < subLength; n++) {
              if (window.pageCurrentData[i]['items'][result.index][n]['basis']['caption'] === elements[j]) {
                if (result.audit.ok == false) {
                  !this.firstErr && (this.firstErr = {
                    id: id,
                    index: i,
                    msg: result.audit.errorMsg,
                    pid: window.pageCurrentData[i]['items'][result.index][n]['basis']['pid'],
                    itemIndex: result.index
                  });
                  let newAudit = null;
                  if (window.pageCurrentData[i]['items'][result.index][n]['basis']['caption'] === id && !exist) {
                    newAudit = {
                      "key": result.key,  //规则的key
                      "errorMsg": result.audit.errorMsg,  //规则中的错误文字
                      "remark": "",    //用户填写的备注
                      "level": result.audit.level,  //规则中的错误级别
                      "index": result.index,  //规则中表示子表的行索引
                      "updateUserName": "",   //填写或者修改备注的用户姓名
                      "updateUserId": "" //填写或者修改备注的用户ID
                    };
                    this.setNewAudit(newAudit);
                    auditResult.push(newAudit);
                  }
                  if (newAudit && newAudit.level == 0 && newAudit.remark) {
                    window.pageCurrentData[i]['items'][result.index][n]['error'] = false;
                    window.pageCurrentData[i]['items'][result.index][n]['errorMsg'] = result.audit.errorMsg;
                  } else {
                    window.pageCurrentData[i]['items'][result.index][n]['error'] = !result.audit.ok;
                    window.pageCurrentData[i]['items'][result.index][n]['errorMsg'] = result.audit.errorMsg;
                  }
                } else {
                  //当检验结果正确时，将上一次审核结果集中存在对应key的结果变更
                  for (let k = 0, relLength = this.auditInfo.result.detail.length; k < relLength; k++) {
                    if (this.auditInfo.result.detail[k]['key'] === result['key']) {
                      //判断是否存在别的审核导致的错误
                      let has = this.hasOtherErr(auditResult, elements);
                      if (has.length === 0) {
                        window.pageCurrentData[i]['items'][result.index][n]['error'] = !result.audit.ok;
                        window.pageCurrentData[i]['items'][result.index][n]['errorMsg'] = result.audit.errorMsg;
                      }
                      break;
                    }
                  }
                }
              }
            }
          } else {
            if (elements[j] === window.pageCurrentData[i]['basis']['caption']) {
              if (result.audit.ok == false) {
                !this.firstErr && (this.firstErr = {
                  id: id,
                  index: i,
                  msg: result.audit.errorMsg
                });
                let newAudit = null;
                if (window.pageCurrentData[i]['basis']['caption'] === id && !exist) {
                  newAudit = {
                    "key": result.key,  //规则的key
                    "errorMsg": result.audit.errorMsg,  //规则中的错误文字
                    "remark": "",    //用户填写的备注
                    "level": result.audit.level,  //规则中的错误级别
                    "index": undefined,  //规则中表示子表的行索引
                    "updateUserName": "",   //填写或者修改备注的用户姓名
                    "updateUserId": "" //填写或者修改备注的用户ID
                  };
                  this.setNewAudit(newAudit);
                  auditResult.push(newAudit);
                }
                if (newAudit && newAudit.level == 0 && newAudit.remark) {
                  window.pageCurrentData[i]['error'] = false;
                  window.pageCurrentData[i]['errorMsg'] = result.audit.errorMsg;
                } else {
                  window.pageCurrentData[i]['error'] = !result.audit.ok;
                  window.pageCurrentData[i]['errorMsg'] = result.audit.errorMsg;
                }
              } else {
                //当检验结果正确时，将上一次审核结果集中存在对应key影响的数据项error变更
                for (let k = 0, relLength = this.auditInfo.result.detail.length; k < relLength; k++) {
                  if (this.auditInfo.result.detail[k]['key'] === result['key']) {
                    let has = this.hasOtherErr(auditResult, elements);
                    if (has.length === 0) {
                      window.pageCurrentData[i]['error'] = !result.audit.ok;
                      window.pageCurrentData[i]['errorMsg'] = result.audit.errorMsg;
                    }
                    break;
                  }
                }
              }
            }
          }
        }
      }
    },
    /**
     * 判断是否有其他审核导致的错误
     * @param auditResult 当前审核结果
     * @param elements 当前错误影响的控件
     * @returns {*|Array|Array}
     */
    hasOtherErr(auditResult, elements) {
      for (let i = 0, length = auditResult.length; i < length; i++) {
        for (let j = 0, leng = window.ev.evList.length; j < leng; j++) {
          if (window.ev.evList[j]['key'] === auditResult[i]['key']) {
            let arr = this.getArrEqual(window.ev.evList[j]['rel'], elements);
            if (arr.length > 0) {
              return arr
            }
          }
        }
      }
      return []
    },
    //获取两个数组相同项
    getArrEqual(arr1, arr2) {
      let newArr = [];
      for (let i = 0; i < arr2.length; i++) {
        for (let j = 0; j < arr1.length; j++) {
          if (arr1[j] === arr2[i]) {
            newArr.push(arr1[j]);
          }
        }
      }
      return newArr;
    },
    //设置新审核结果备注
    setNewAudit(audit) {
      for (let n = 0, length = this.auditInfo.result.detail.length; n < length; n++) {
        if (this.auditInfo.result.detail[n]['key'] === audit['key'] && this.auditInfo.result.detail[n]['index'] == audit['index']) {
          audit['remark'] = this.auditInfo.result.detail[n]['remark'];
          return
        }
      }
    },
  }
}

