import Vue from 'vue'
import App from './question.vue'
import axios from '@/lib/http'
import store from '@/store'
import '@/lib/flexble'
import '@/lib/window'
import '@/assets/css/common.less'

import {
  NavBar,
  Button,
  DatetimePicker,
  Toast,
  Field,
  Cell,
  CellGroup,
  RadioGroup,
  Radio,
  Checkbox,
  CheckboxGroup,
  Popup,
  Picker,
  Rate,
  Slider,
  Actionsheet,
  Uploader,
  Icon,
} from 'vant'

Vue.use(axios).use(Button).use(Toast).use(NavBar).use(Field).use(Cell).use(CellGroup).use(RadioGroup)
    .use(Checkbox).use(CheckboxGroup).use(Radio).use(Picker).use(Popup).use(DatetimePicker).use(Slider).use(Rate)
    .use(Actionsheet).use(Uploader).use(Icon)

Vue.config.productionTip = false

// load进度条
import NProgress from 'nprogress'
import 'nprogress/nprogress.css'

NProgress.configure({easing: 'ease-in', minimum: 0.1, showSpinner: false});

import Load from '@/components/common/Load'

Vue.component("Load", Load);

import Router from 'vue-router'
Vue.use(Router);

const router = new Router({
  routes: [
    //  问卷
    {
      path: '/',
      alias:'/index',
      name: 'Question',
      component: require('@/views/question/Index.vue').default,
    },
    {
      path: '/empty',
      name: 'Empty',
      component: require('@/views/Empty.vue').default,
    },
    //  404
    {
      path: '*',//404
      component: require('@/views/404.vue').default
    }
  ]
})

//路由监听
router.beforeEach((to, from, next) => {
  NProgress.start();
  next();
})
router.afterEach((to, from) => {
  NProgress.done()
})

new Vue({
  router,
  store,
  render: h => h(App),
}).$mount('#app')
