<template>
  <!--  bgColor="#1989fa"-->
  <Load v-if="currentData.length===0"></Load>
  <div v-else class="van-second-box question-box no-padding-bottom">
    <div v-if="showMarker" class="readonly-box"></div>
    <Question v-for="(item,index) in currentData" :key="index" :question="item" @hidden="hidden"
              @btnClick="btnClick"></Question>
  </div>
</template>

<script>
  import dom from '../../lib/domData'
  import form from '../../lib/form'
  import Question from '@/components/question/QuestionItem'

  export default {
    name: "QuesIndex",
    extends: form,
    mixins: [dom],
    data() {
      return {
        isQuestion: true,
        showMarker: false, //全屏遮罩层
      }
    },
    created() {
      // this.isQuestion = this.$route.path.includes('question');
      //模拟登陆
      if (this.$route.query.userID && this.$route.query.userType) {
        this.$http.post("dsfa/teas/cms/main/userlogin/loginByUserIdAndType", {
          userType: this.$route.query.userType,
          userId: this.$route.query.userID
        });
      }
    },
    updated() {
      this.$nextTick(function () {
        if (typeof window.domReady === 'function') {
          window.domReady();
        }
      });
    },
    computed: {},
    components: {Question},
    methods: {
      /**
       * curr: 当前题目的标识id
       * trig：目标题序号（执行state的题目）
       * state 触发时在组件内判定是否隐藏 true:是 false:否
       **/
      hidden(curr, trig, state) {
        for (let i = 0, length = this.currentData.length; i < length; i++) {
          //只针对会被当前题影响的题目进行判断
          if (this.currentData[i]['qid'] != trig) {
            continue
          }
          //操作触发隐藏数组增加或删除当前题目序号
          let index = this.currentData[i]['trigHide'].indexOf(curr);
          if (state) {
            if (index === -1) {
              this.currentData[i]['trigHide'].push(curr);
            }
          } else {
            if (index > -1) {
              this.currentData[i]['trigHide'].splice(index, 1);
            }
          }
          //检测
          this.setIsHide(this.currentData[i]);
          //若设置隐藏，则检测之后的题目是否被trig题影响
          this.checkAfterHidden(i + 1, trig, this.currentData[i]['hidden']);
          //对目标题操作后跳出循环
          break;
        }
      },
      setIsHide(currentData) {
        //判断trigHide是否为空数组，决定hidden控制显隐
        if (currentData['trigHide'].length === 0) {
          currentData['hidden'] = false;
        } else {
          currentData['hidden'] = true;
        }
      },
      checkAfterHidden(i, trig, hidden) {
        for (let length = this.currentData.length; i < length; i++) {
          //只针对表单元素检测
          if (this.currentData[i]['trigHide'] && this.currentData[i]['waitTrig']) {
            //隐藏:从trigHide弹出push到waitTrig
            if (hidden) {
              let index = this.currentData[i]['trigHide'].indexOf(trig);
              if (index > -1) {
                this.currentData[i]['trigHide'].splice(index, 1);
                this.currentData[i]['waitTrig'].push(trig);
              } else {
              }
            } else {
              //显示：从waitTrig弹出push到trigHide
              let index = this.currentData[i]['waitTrig'].indexOf(trig);
              if (index > -1) {
                this.currentData[i]['waitTrig'].splice(index, 1);
                this.currentData[i]['trigHide'].push(trig);
              } else {
              }
            }
            this.setIsHide(this.currentData[i]);
          }
        }
      },
      /**
       * 问卷数据组合
       * @param dom 原页面数据
       * @param dataSource 表单源数据
       */
      initDomData(dom, dataSource) {
        console.info('节点数据：', dom);
        // console.info('源数据：', dataSource);
        // console.info('问卷数据：', this.$store.state.subForm);

        let pageArr = [];//每一页暂存数据
        this.$store.commit('initQues');//清空题库

        const forms = ['QsRadio', 'Fill', 'QsCheckBox', 'QsRate', 'QsSlider', 'QA'];
        //判断类型，是否是题目
        for (let i = 0, length = dom.length; i < length; i++) {
          if(dom[i]['ctrl_type'] === 'QsTitle'){
            dom[i]['ctrl_type'] = 'QsHelloMsg';
          }
          //暂存数据对象,共有属性
          let obj = {
            basis: {
              id: dom[i]['metadata_fullcode'],//唯一id
              ctrl_type: dom[i]['ctrl_type'],
              visible: dom[i]['$visible'], //是否隐藏
              label: dom[i]['$questionBody'] || '问题',
              index: dom[i]['$questionIndex'],//用于显示的索引
            },
            qid: dom[i]['$questionIndex'],
            value: dom[i]['$value'] || "",
            hidden: false,//跳转后触发的隐藏，仅在visible生效
          };
          //私有属性初始化
          //按钮组
          if (dom[i]['$buttonBar']) {
            delete obj.basis.index;
            obj['buttons'] = dom[i]['$buttonBar']['buttons'];
          } else if (dom[i]['ctrl_type'].includes('Upload')) {//上传相关
            obj['multiple'] = dom[i]['$multiple'];
            obj['uploadFileNum'] = dom[i]['$uploadFileNum'] || 1;
            obj['max'] = dom[i]['$maxFileSize'] ? parseInt(dom[i]['$maxFileSize']) * 1024 : 0;//0为无限制
            dom[i]['$uploadFileType'] && (obj['uploadFileType'] = dom[i]['$uploadFileType']);
            obj['accept'] = '*image/' + (dom[i]['$uploadFileExts'] || '*');
          } else if (forms.indexOf(dom[i]['ctrl_type']) > -1) {//表单元素
            obj['trigHide'] = [];//触发隐藏的题目集合
            obj['waitTrig'] = [];//当触发显示后需要push到trigHide的题目集合
            obj['basis']['bindValue'] = true;//是否需要绑定value
            obj['error'] = false;//是否有错误
            obj['errorMsg'] = `请作答${dom[i]['$questionIndex']}题`;//错误提示
            obj['basis']['readOnly'] = dom[i]['$readOnly'];
            obj['basis']['required'] = dom[i]['$required'];
            obj['basis']['questionBody'] = dom[i]['$questionBody'] || "";
            obj['basis']['showLabel'] = true;//必显示题目
            //题型特殊处理
            if (dom[i]['ctrl_type'] === 'QA') {
              obj['basis']['placeholder'] = dom[i]['$placeholder'] || '请作答';
              obj['basis']['ishideCon'] = dom[i]['$ishideCon'] || false;//密码框
              dom[i]['$isTextArea'] && (obj['basis']['type'] = 'textarea');
              dom[i]['maxL'] = dom[i]['$maxLength'];
              // obj['basis']['hideLabel'] = true;
            }
            if (dom[i]['ctrl_type'] === 'QsSlider') {
              obj['basis']['max'] = +dom[i]['$max'];
              obj['basis']['min'] = +dom[i]['$min'];
              obj['basis']['step'] = +dom[i]['$step'];
            }
            if (dom[i]['ctrl_type'] === 'QsRate') {
              obj['basis']['count'] = +dom[i]['$StarLength'];
            }
            if (dom[i]['ctrl_type'] === 'QsCheckBox') {
              obj['basis']['maxCheckNum'] = dom[i]['$maxCheckNum'];
            }
            //默认显示
            let defaultAns = this.$store.state.answers[dom[i]['metadata_fullcode']];
            if (defaultAns) {
              //文本框做特殊处理
              if (dom[i]['ctrl_type'] === 'QA') {
                obj['value'] = defaultAns;
              } else {
                obj['basis']['defaultValue'] = defaultAns;
              }
            } else {
              //未填写则显示默认值
              if (!!dom[i]['$metadata'] && !!dom[i]['$metadata']['defaultValue']) {
                obj['basis']['defaultValue'] = dom[i]['$metadata']['defaultValue'];
              } else {
                obj['basis']['defaultValue'] = null;
              }
            }
            //数据源
            if (!!dataSource && dataSource[obj['basis']['id']] && dataSource[obj['basis']['id']]['dataSource']) {
              obj['dataSource'] = dataSource[obj['basis']['id']]['dataSource'];
            }
            //是否含有其他选项,必须在设置数据源后设置
            if (dom[i]['ctrl_type'] === 'QsCheckBox' || dom[i]['ctrl_type'] === 'QsRadio') {
              obj['logic'] = dom[i]['$logic'];//跳转逻辑
              if (dom[i]['$isOther']) {
                obj['dataSource'].push({
                  text: '其他',
                  value: 'else'
                });
                obj['otherText'] = "";
              }
            }
            //验证规则
            if (dom[i]['ctrl_type'] !== 'QsRate' && dom[i]['ctrl_type'] !== 'QsSlider' && !!dom[i]['$metadata'] && !!dom[i]['$metadata']['validate']['config']) {
              obj['basis']['validate'] = dom[i]['$metadata']['validate']['config'];
            }
          } else if (dom[i]['ctrl_type'] === 'QsHelloMsg') {
            obj['value'] = obj['basis']['label'];
            Object.freeze(obj);
          } else {
            //只用作显示相关,取消vue劫持
            Object.freeze(obj);
          }
          pageArr.push(obj);

          //判断题目集合是否分页
          // if ((i + 1) % 4 === 0 || i + 1 === length) {
          //   //推入题库并重置暂存数组
          //   this.$store.commit("addQues", pageArr);
          //   pageArr = [];
          // }
        }
        //启用分页，屏蔽此处commit
        this.$store.commit("addQues", pageArr);
        //初始化当前页
        this.currentData = this.$store.state.questions[0];
        if (this.$store.state.questions.length === 1) {
          // this.btnTxt = '提交问卷';
          this.isLast = true;
        }
        this.changeReadonly(this.$route.query.readonly);
      },
      // 切换只读的方法
      changeReadonly(type){
        type = (type===1||type==="1")?true:false;
        if(type){
          this.showMarker = true;
          this.currentData[this.currentData.length-1].hidden = true
        }else{
          this.showMarker = false;
          this.currentData[this.currentData.length-1].hidden = false
        }
      }
    }
  }
</script>
